    test('caps oversized base durations before scaling milliseconds', () {
      final milliseconds = AutoExploreLegDuration.milliseconds(
        baseDuration: const Duration(milliseconds: 9223372036855),
        scale: 1.0,
        speed: 1.0,
      );

      expect(milliseconds, 9223372036854);
    });

    test('sanitizes invalid duration scale before rounding milliseconds', () {
      const nanScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.nan,
        ),
      );
      const infiniteScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.infinity,
        ),
      );
      const belowNeutralScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 0.0,
        ),
      );
      const overflowingFiniteScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 1e308,
        ),
      );
      const finiteButDurationOverflowingPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 1e16,
        ),
      );

      for (final planner in [
        nanScalePlanner,
        infiniteScalePlanner,
        belowNeutralScalePlanner,
        overflowingFiniteScalePlanner,
        finiteButDurationOverflowingPlanner,
      ]) {
        expect(
          planner.durationForZoomLeg(
            startZoom: 1.0,
            endZoom: 1e6,
            speed: 1.0,
          ),
          const Duration(milliseconds: 1000),
        );
      }
    });
  });
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreService', () {
    test('dispose cancels without sending a playback update', () {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(controller.dispose);

      var notifications = 0;
      service.addListener(() => notifications++);

      service.dispose();

      expect(notifications, 0);
    });

    test('ignores one-shot corrections during continuous user interaction',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);

      controller.updateZoom(2.0);
      service.onUserCorrection();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.onUserInteractionEnd();

      expect(service.pausedByUserCorrection, isFalse);
    });

    test('toggle resumes from temporary user yield instead of pausing',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.toggle();

      expect(service.isExploring, isTrue);
      expect(service.isPaused, isFalse);
      expect(service.pausedByUserCorrection, isFalse);
    });

    test('resume replans from a zoom changed while paused', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.pause();

      controller.updateZoom(10.0);
      service.resume();

      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 1200.0);
    });

    test('ignores unmatched continuous interaction end callbacks', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 120.0);

      service.onUserInteractionEnd();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, AutoExploreConfig.defaultMinZoom);
    });
  });
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

/// Provenance for the custom export dimension that wins resolution.
enum CustomExportDimensionSource {
  fieldText,
  currentValue,
  fallback,
}

/// Replayable result of resolving one custom export dimension.
///
/// The export model clamps target dimensions later, but the sheet summary and
/// submission payload read [ExportOptions.customWidth]/customHeight directly.
/// Keep that boundary normalized too so all export dimension paths share the
/// same safety contract.
final class CustomExportDimensionResolution {
  const CustomExportDimensionResolution({
    required this.value,
    required this.source,
    required this.wasClamped,
  });

  final int value;
  final CustomExportDimensionSource source;
  final bool wasClamped;
}

CustomExportDimensionResolution resolveCustomExportDimensionPlan({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  return _normalizeCustomExportDimension(
        parsed,
        source: CustomExportDimensionSource.fieldText,
      ) ??
      _normalizeCustomExportDimension(
        currentValue,
        source: CustomExportDimensionSource.currentValue,
      ) ??
      _normalizeFallbackCustomExportDimension(fallback);
}

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  return resolveCustomExportDimensionPlan(
    fieldText: fieldText,
    currentValue: currentValue,
    fallback: fallback,
  ).value;
}

CustomExportDimensionResolution? _normalizeCustomExportDimension(
  int? value, {
  required CustomExportDimensionSource source,
}) {
  final normalized = ExportDimensionPolicy.positiveCustomDimension(value);
  if (normalized == null) return null;

  return CustomExportDimensionResolution(
    value: normalized,
    source: source,
    wasClamped: normalized != value,
  );
}

CustomExportDimensionResolution _normalizeFallbackCustomExportDimension(
  int fallback,
) {
  final safeFallback = fallback > 0 ? fallback : 1;
  final normalized = ExportDimensionPolicy.positiveCustomDimension(
    safeFallback,
  )!;

  return CustomExportDimensionResolution(
    value: normalized,
    source: CustomExportDimensionSource.fallback,
    wasClamped: normalized != fallback,
  );
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/features/export/custom_export_dimensions.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('resolveCustomExportDimension', () {
    test('uses positive field text before current value or fallback', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '2048',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        2048,
      );
    });

    test('falls back to current value when field text is invalid', () {
      expect(
        resolveCustomExportDimension(
          fieldText: 'not a number',
          currentValue: 1024,
          fallback: defaultCustomExportWidth,
        ),
        1024,
      );
    });

    test('normalizes oversized field text through export dimension policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '${1 << 40}',
          currentValue: null,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });

    test('normalizes oversized current value fallback through policy', () {
      expect(
        resolveCustomExportDimension(
          fieldText: '',
          currentValue: 1 << 40,
          fallback: defaultCustomExportWidth,
        ),
        ExportDimensionPolicy.maxPixelDimension,
      );
    });
  });

  group('resolveCustomExportDimensionPlan', () {
    test('exposes winning source and clamp provenance', () {
      final clampedField = resolveCustomExportDimensionPlan(
        fieldText: '${1 << 40}',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );
      final currentFallback = resolveCustomExportDimensionPlan(
        fieldText: '0',
        currentValue: 1024,
        fallback: defaultCustomExportWidth,
      );

      expect(clampedField.value, ExportDimensionPolicy.maxPixelDimension);
      expect(clampedField.source, CustomExportDimensionSource.fieldText);
      expect(clampedField.wasClamped, isTrue);
      expect(currentFallback.value, 1024);
      expect(currentFallback.source, CustomExportDimensionSource.currentValue);
      expect(currentFallback.wasClamped, isFalse);
    });
  });

  group('withResolvedCustomExportDimensions', () {
    test('stores normalized custom dimensions in the export payload', () {
      final resolved = withResolvedCustomExportDimensions(
        options: const ExportOptions(
          resolution: ExportResolution.custom,
          customWidth: 1 << 40,
          customHeight: 720,
        ),
        widthText: '',
        heightText: '${1 << 35}',
      );

      expect(resolved.customWidth, ExportDimensionPolicy.maxPixelDimension);
      expect(resolved.customHeight, ExportDimensionPolicy.maxPixelDimension);
    });
  });
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';

/// Replayable presentation and update contract for numeric parameter controls.
///
/// The controls sheet receives dynamic `Object` values from controller state.
/// Keeping slider normalization, label formatting, division calculation, and
/// emitted values together prevents the visible label from drifting away from
/// the clamped slider position when stale/replayed values are malformed.
final class NumericParamControlPlan {
  const NumericParamControlPlan._({
    required this.type,
    required this.range,
    required this.value,
    required this.divisions,
    required this.valueLabel,
    required this.floatPrecision,
  });

  factory NumericParamControlPlan.fromParam({
    required FractalParameter param,
    required Object value,
  }) {
    assert(
      param.type == FractalParamType.float ||
          param.type == FractalParamType.integer,
      'NumericParamControlPlan only supports numeric parameter types',
    );

    final range = NumericParamControlRange.fromParam(param);
    final rawValue = _finiteNumericValue(value) ??
        _finiteNumericValue(param.defaultValue) ??
        range.min;
    final sliderValue = range.clamp(rawValue);
    final floatPrecision = NumericParamFloatPrecision.fromStep(param.step);

    return NumericParamControlPlan._(
      type: param.type,
      range: range,
      value: sliderValue,
      divisions: range.divisionsForStep(param.step),
      valueLabel: _labelFor(
        type: param.type,
        range: range,
        sliderValue: sliderValue,
        floatPrecision: floatPrecision,
      ),
      floatPrecision: floatPrecision,
    );
  }

  final FractalParamType type;
  final NumericParamControlRange range;

  /// Clamped finite value that is safe to pass to [Slider.value].
  final double value;

  /// Slider divisions, or null when the schema step cannot form divisions.
  final int? divisions;

  /// Label for the same normalized value shown by the slider.
  final String valueLabel;

  /// Float formatting/emission precision derived from the schema step.
  final NumericParamFloatPrecision floatPrecision;

  double get min => range.min;
  double get max => range.max;

  Object valueForSliderPosition(double sliderPosition) {
    final clamped = range.clamp(sliderPosition);
    return switch (type) {
      FractalParamType.integer => range.integerValueFor(clamped),
      FractalParamType.float => floatPrecision.round(clamped),
      FractalParamType.boolean || FractalParamType.enumeration => clamped,
    };
  }

  static String _labelFor({
    required FractalParamType type,
    required NumericParamControlRange range,
    required double sliderValue,
    required NumericParamFloatPrecision floatPrecision,
  }) {
    if (type == FractalParamType.integer) {
      return range.integerValueFor(sliderValue).toString();
    }
    return floatPrecision.format(sliderValue);
  }

  static double? _finiteNumericValue(Object value) {
    if (value is! num) return null;
    final numericValue = value.toDouble();
    return numericValue.isFinite ? numericValue : null;
  }
}

/// Sanitized numeric range for a parameter slider.
final class NumericParamControlRange {
  const NumericParamControlRange({
    required this.min,
    required this.max,
  });

  factory NumericParamControlRange.fromParam(FractalParameter param) {
    final safeMin = param.min.isFinite ? param.min : 0.0;
    final safeMax = param.max.isFinite ? param.max : safeMin;

    if (safeMin <= safeMax) {
      return NumericParamControlRange(min: safeMin, max: safeMax);
    }
    return NumericParamControlRange(min: safeMax, max: safeMin);
  }

  final double min;
  final double max;

  double get span => max - min;

  double clamp(double value) {
    if (!value.isFinite) return min;
    return value.clamp(min, max).toDouble();
  }

  int? divisionsForStep(double step) {
    if (span <= 0.0 || !step.isFinite || step <= 0.0) return null;

    final rawDivisions = span / step;
    if (!rawDivisions.isFinite) return null;

    final divisions = rawDivisions.round();
    return divisions > 0 ? divisions : null;
  }

  int integerValueFor(double sliderPosition) {
    final rounded = clamp(sliderPosition).round();
    final lower = min.ceil();
    final upper = max.floor();
    if (lower > upper) return rounded;
    return rounded.clamp(lower, upper).toInt();
  }
}

/// Float label/update precision derived from a slider schema step.
///
/// The old control contract used a hard-coded two decimal places for every
/// float. Some module parameters declare finer steps (for example 0.001), so
/// replayed slider positions must retain at least the precision the schema
/// promises while preserving the existing two-decimal minimum for coarser
/// controls.
final class NumericParamFloatPrecision {
  static const int defaultFractionDigits = 2;
  static const int maxFractionDigits = 12;
  static const double _integerTolerance = 1e-9;

  const NumericParamFloatPrecision._(this.fractionDigits);

  factory NumericParamFloatPrecision.fromStep(double step) {
    if (!step.isFinite || step <= 0.0 || step >= 1.0) {
      return const NumericParamFloatPrecision._(defaultFractionDigits);
    }

    for (var digits = defaultFractionDigits;
        digits <= maxFractionDigits;
        digits++) {
      final scale = pow(10.0, digits).toDouble();
      final scaledStep = step * scale;
      if (!scaledStep.isFinite) break;
      if ((scaledStep - scaledStep.round()).abs() <= _integerTolerance) {
        return NumericParamFloatPrecision._(digits);
      }
    }

    return const NumericParamFloatPrecision._(defaultFractionDigits);
  }

  final int fractionDigits;

  double round(double value) => double.parse(format(value));

  String format(double value) => value.toStringAsFixed(fractionDigits);
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/controls/param_control_plan.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1,
  double max = 10,
  double step = 1,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: step,
    defaultValue: defaultValue,
  );
}

void main() {
  group('NumericParamControlPlan', () {
    test('uses the clamped slider value for integer labels and updates', () {
      final plan = NumericParamControlPlan.fromParam(
        param: _numericParam(
          type: FractalParamType.integer,
          defaultValue: 5,
          min: 1,
          max: 10,
        ),
        value: 99,
      );

      expect(plan.value, 10);
      expect(plan.valueLabel, '10');
      expect(plan.valueForSliderPosition(99), 10);
    });

    test('falls back to numeric defaults for non-finite values', () {
      final plan = NumericParamControlPlan.fromParam(
        param: _numericParam(
          type: FractalParamType.float,
          defaultValue: 4.25,
          min: 1,
          max: 10,
          step: 0.25,
        ),
        value: double.nan,
      );

      expect(plan.value, 4.25);
      expect(plan.valueLabel, '4.25');
    });

    test('uses schema step precision for fine-grained float labels and updates',
        () {
      final plan = NumericParamControlPlan.fromParam(
        param: _numericParam(
          type: FractalParamType.float,
          defaultValue: 0.0,
          min: -2,
          max: 2,
          step: 0.001,
        ),
        value: 1.234,
      );

      expect(plan.value, 1.234);
      expect(plan.valueLabel, '1.234');
      expect(plan.valueForSliderPosition(-1.234), -1.234);
    });

    test('does not derive slider divisions from malformed steps', () {
      for (final step in [0.0, -1.0, double.nan, double.infinity]) {
        final plan = NumericParamControlPlan.fromParam(
          param: _numericParam(
            type: FractalParamType.float,
            defaultValue: 5.0,
            step: step,
          ),
          value: 5.0,
        );

        expect(plan.divisions, isNull, reason: 'step=$step');
      }
    });

    test('integer emissions honor fractional numeric bounds', () {
      final plan = NumericParamControlPlan.fromParam(
        param: _numericParam(
          type: FractalParamType.integer,
          defaultValue: 4,
          min: 1.2,
          max: 10.8,
        ),
        value: 1.2,
      );

      expect(plan.valueLabel, '2');
      expect(plan.valueForSliderPosition(1.2), 2);
      expect(plan.valueForSliderPosition(10.8), 10);
    });
  });

  group('NumericParamControlRange', () {
    test('sanitizes reversed and non-finite schema bounds for replay', () {
      final reversed = NumericParamControlRange.fromParam(
        _numericParam(
          type: FractalParamType.float,
          defaultValue: 5.0,
          min: 10,
          max: 1,
        ),
      );
      final nonFinite = NumericParamControlRange.fromParam(
        _numericParam(
          type: FractalParamType.float,
          defaultValue: 5.0,
          min: double.nan,
          max: double.infinity,
        ),
      );

      expect(reversed.min, 1);
      expect(reversed.max, 10);
      expect(nonFinite.min, 0);
      expect(nonFinite.max, 0);
    });
  });
}

import 'package:flutter_fractals/features/catalog/catalog_entry.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// Replayable catalog search query used by the catalog screen.
///
/// The UI debounces text input, then filters entries by localized display name,
/// aliases, stable catalog ID, and category. Keeping the case/whitespace
/// normalization in one pure value object makes search behavior testable without
/// pumping the whole catalog widget.
final class CatalogSearchQuery {
  const CatalogSearchQuery._(this.value);

  factory CatalogSearchQuery.fromText(String text) {
    return CatalogSearchQuery._(text.trim().toLowerCase());
  }

  /// Lower-case, trimmed query text.
  final String value;

  bool get isEmpty => value.isEmpty;

  bool matches(CatalogEntry entry, AppLocalizations l10n) {
    if (isEmpty) return true;

    return _searchableFields(entry, l10n).any(
      (field) => field.toLowerCase().contains(value),
    );
  }

  Iterable<String> _searchableFields(
    CatalogEntry entry,
    AppLocalizations l10n,
  ) sync* {
    yield entry.module.displayName(l10n);
    yield* entry.aliases;
    yield entry.catalogId;
    yield entry.category;
  }
}

