import 'dart:convert';

import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_palette.dart';

class PaletteStore {
  static const _key = 'user_palettes_v1';

  final SharedPreferences _prefs;

  PaletteStore._(this._prefs);

  static Future<PaletteStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PaletteStore._(prefs);
  }

  List<FractalPalette> loadPalettes() {
    return _decodePalettePayload(_prefs.get(_key));
  }

  List<FractalPalette> _decodePalettePayload(Object? payload) {
    if (payload == null) return const [];
    if (payload is String) return _decodeLegacyPaletteArray(payload);
    if (payload is List) return _decodePaletteListPayload(payload);
    return const [];
  }

  List<FractalPalette> _decodePaletteListPayload(List<Object?> payload) {
    final encodedPalettes = <String>[];
    for (final entry in payload) {
      if (entry is! String) return const [];
      encodedPalettes.add(entry);
    }
    return _decodePaletteStringList(encodedPalettes);
  }

  List<FractalPalette> _decodePaletteStringList(List<String> encodedPalettes) {
    final palettes = <FractalPalette>[];
    for (final encoded in encodedPalettes) {
      final palette = _tryDecodePaletteString(encoded);
      if (palette != null && palette.id.isNotEmpty) palettes.add(palette);
    }
    return palettes;
  }

  FractalPalette? _tryDecodePaletteString(String encoded) {
    try {
      return FractalPalette.fromJsonString(encoded);
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] skipping palette entry: $e');
      return null;
    }
  }

  List<FractalPalette> _decodeLegacyPaletteArray(String? payload) {
    if (payload == null || payload.trim().isEmpty) return const [];

    try {
      final decodedArr = (jsonDecode(payload) as List).cast<Map>();
      return decodedArr
          .map((m) => FractalPalette.fromJson(m.cast<String, Object?>()))
          .where((p) => p.id.isNotEmpty)
          .toList();
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] silent catch: $e');
      return const [];
    }
  }

  Future<void> savePalettes(List<FractalPalette> palettes) async {
    final list = palettes.map((p) => p.toJsonString(pretty: false)).toList();
    await _prefs.setStringList(_key, list);
  }
}

import 'dart:convert';

import 'package:flutter_fractals/core/models/fractal_palette.dart';
import 'package:flutter_fractals/core/services/palette_store.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';

void main() {
  setUp(() {
    TestWidgetsFlutterBinding.ensureInitialized();
    SharedPreferences.setMockInitialValues({});
  });

  group('PaletteStore', () {
    test('loadPalettes returns empty list when no data', () async {
      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();
      expect(palettes, isEmpty);
    });

    test('savePalettes and loadPalettes round-trip', () async {
      final store = await PaletteStore.create();

      final palettes = [
        const FractalPalette(
          id: 'pal-1',
          name: 'Fire',
          stops: [
            FractalColorStop(position: 0.0, colorArgb: 0xFFFF0000),
            FractalColorStop(position: 1.0, colorArgb: 0xFFFFFF00),
          ],
        ),
        const FractalPalette(
          id: 'pal-2',
          name: 'Ocean',
          stops: [
            FractalColorStop(position: 0.0, colorArgb: 0xFF0000FF),
            FractalColorStop(position: 1.0, colorArgb: 0xFF00FFFF),
          ],
        ),
      ];

      await store.savePalettes(palettes);
      final loaded = store.loadPalettes();

      expect(loaded.length, 2);
      expect(loaded[0].id, 'pal-1');
      expect(loaded[0].name, 'Fire');
      expect(loaded[0].stops.length, 2);
      expect(loaded[0].stops[0].colorArgb, 0xFFFF0000);
      expect(loaded[0].stops[1].colorArgb, 0xFFFFFF00);

      expect(loaded[1].id, 'pal-2');
      expect(loaded[1].name, 'Ocean');
      expect(loaded[1].stops[0].colorArgb, 0xFF0000FF);
    });

    test('savePalettes and loadPalettes preserves stop positions', () async {
      final store = await PaletteStore.create();

      final palette = const FractalPalette(
        id: 'gradient',
        name: 'Gradient',
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF),
          FractalColorStop(position: 0.5, colorArgb: 0xFF888888),
          FractalColorStop(position: 1.0, colorArgb: 0xFF000000),
        ],
      );

      await store.savePalettes([palette]);
      final loaded = store.loadPalettes();

      expect(loaded.length, 1);
      expect(loaded[0].stops[1].position, closeTo(0.5, 1e-9));
    });

    test('loadPalettes skips corrupted string-list entries', () async {
      final goodEntry = const FractalPalette(
        id: 'ok',
        name: 'Good',
        stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
      ).toJsonString(pretty: false);

      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': <String>['not valid json {{{{', goodEntry],
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();

      expect(palettes, hasLength(1));
      expect(palettes.single.id, 'ok');
    });

    test('loadPalettes loads legacy JSON array payloads', () async {
      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': jsonEncode([
          const FractalPalette(
            id: 'legacy',
            name: 'Legacy',
            stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
          ).toJson(),
        ]),
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();

      expect(palettes, hasLength(1));
      expect(palettes.single.id, 'legacy');
      expect(palettes.single.name, 'Legacy');
    });

    test('loadPalettes skips palettes with empty id', () async {
      // Use the List<String> primary path: two serialised palette JSON strings,
      // one with an empty id (should be filtered) and one with a valid id.
      final badEntry = const FractalPalette(
        id: '',
        name: 'Bad',
        stops: [],
      ).toJsonString(pretty: false);
      final goodEntry = const FractalPalette(
        id: 'ok',
        name: 'Good',
        stops: [],
      ).toJsonString(pretty: false);

      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': <String>[badEntry, goodEntry],
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();
      expect(palettes.length, 1);
      expect(palettes.first.id, 'ok');
    });

    test('savePalettes overwrites previous save', () async {
      final store = await PaletteStore.create();

      final first = [
        const FractalPalette(
          id: 'first',
          name: 'First',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFF0000)],
        ),
      ];
      final second = [
        const FractalPalette(
          id: 'second',
          name: 'Second',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFF00FF00)],
        ),
      ];

      await store.savePalettes(first);
      await store.savePalettes(second);
      final loaded = store.loadPalettes();

      expect(loaded.length, 1);
      expect(loaded.first.id, 'second');
    });

    test('savePalettes with empty list clears palettes', () async {
      final store = await PaletteStore.create();

      final palettes = [
        const FractalPalette(
          id: 'p1',
          name: 'P1',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
        ),
      ];
      await store.savePalettes(palettes);
      await store.savePalettes([]);
      final loaded = store.loadPalettes();

      expect(loaded, isEmpty);
    });
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_repository.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogRepository', () {
    test('creates stable prefixed IDs from module registry', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.entries, isNotEmpty);
      expect(repo.entries.length, registry.modules.length);
      expect(repo.entries.first.catalogId, startsWith('core.'));
      expect(repo.byCatalogId('core.mandelbrot').module.id, 'mandelbrot');
    });

    test('catalog IDs are unique', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.allIds().length, repo.entries.length);
    });

    test('keeps intended 3D runtime modules for implemented 3D catalog ids', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(
        repo.byCatalogId('core.quaternion_julia_3d').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.dual_quaternion_julia').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.mandelbox_shape_inversion').module.dimension,
        FractalDimension.threeD,
      );
    });
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';

/// Stable catalog entry used by the redesigned browser.
///
/// This is intentionally separate from [FractalModule] so we can scale the
/// catalog to many entries (e.g. PRD 200) while still mapping to currently
/// implemented render modules.
@immutable
class CatalogEntry {
  /// Stable ID for catalog persistence, analytics, and deep links.
  ///
  /// Must never change once published.
  final String catalogId;

  /// Backing runtime fractal module that can render this entry today.
  final FractalModule module;

  /// Display category used to group entries in the catalog UI.
  final String category;

  /// Optional search aliases used by catalog filtering.
  final List<String> aliases;

  const CatalogEntry({
    required this.catalogId,
    required this.module,
    required this.category,
    this.aliases = const [],
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/gpu_gradient_module.dart';
import 'package:flutter_fractals/core/modules/gpu_sampler_diag_module.dart';
import 'package:flutter_fractals/core/modules/hydrogen_orbital_module.dart';
import 'package:flutter_fractals/core/modules/julia_dual_module.dart';
import 'package:flutter_fractals/core/modules/julia_module.dart';
import 'package:flutter_fractals/core/modules/mandelbox_module.dart';
import 'package:flutter_fractals/core/modules/mandelbulb_module.dart';
import 'package:flutter_fractals/core/modules/nova_module.dart';
import 'package:flutter_fractals/core/modules/phoenix_module.dart';
import 'package:flutter_fractals/core/modules/test_shaders_module.dart';

/// Registry of all available fractal modules.
///
/// ## Architecture (post-refactor)
///
/// Most 2D escape-time fractals are built **declaratively** from
/// [EscapeTimeConfig] entries in `builders/escape_time/catalog.dart`.
/// Adding a new escape-time fractal = one config entry + one .frag shader.
///
/// Fractals with **custom parameters** (Julia seeds, Phoenix p/q, 3D rotation)
/// still use dedicated builder functions.
///
/// ## How to add a new fractal
///
/// **Standard escape-time (iterations + bailout + color):**
/// 1. Write shader following standard uniform layout (see builders/escape_time/builder.dart)
/// 2. Add `EscapeTimeConfig(...)` to `builders/escape_time/catalog.dart`
/// 3. Register shader in `pubspec.yaml`
/// 4. Done!
///
/// **Custom params or non-escape-time:**
/// 1. Create a `buildXxxModule()` function
/// 2. Add it to [_customModules] below
///
/// {@category Modules}
class ModuleRegistry {
  /// All available fractal modules (built lazily on first access).
  late final List<FractalModule> modules = _buildAll();

  /// Creates the registry.
  ModuleRegistry();

  /// Look up a module by [id]. Throws if not found.
  FractalModule byId(String id) {
    return modules.firstWhere((m) => m.id == id);
  }

  static List<FractalModule> _buildAll() {
    // IDs already in the escape-time catalog (built declaratively).
    // Defensive de-duplication keeps registry stable even if the catalog
    // accidentally contains repeated ids.
    final catalogModules = _dedupeById(buildEscapeTimeCatalogModules());
    final catalogIds = catalogModules.map((m) => m.id).toSet();

    // Custom modules with special params/uniforms
    final customModules = <FractalModule>[
      // Julia needs extra seed params (cx, cy)
      if (!catalogIds.contains('julia')) buildJuliaModule(),
      // Julia Dual: side-by-side Mandelbrot + Julia viewer
      if (!catalogIds.contains('julia_dual')) buildJuliaDualModule(),
      // Phoenix needs extra (p, q) params
      if (!catalogIds.contains('phoenix')) buildPhoenixModule(),
      // Nova needs relaxation param instead of bailout
      if (!catalogIds.contains('nova')) buildNovaModule(),
      // Mandelbulb is 3D with rotation uniforms
      if (!catalogIds.contains('mandelbulb')) buildMandelbulbModule(),
      // Mandelbox is 3D with box-fold + sphere-fold DE
      if (!catalogIds.contains('mandelbox')) buildMandelboxModule(),
      // Hydrogen orbital is a volumetric density renderer with custom controls.
      if (!catalogIds.contains('hydrogen_orbital'))
        buildHydrogenOrbitalModule(),
    ];

    // Diagnostics (debug only, always last)
    final diagModules = kDebugMode
        ? [
            testAlwaysRedModule,
            testUniformOnlyModule,
            testMinimalModule,
            testGlFragCoordModule,
            testFlutterCoordModule,
            buildGpuGradientModule(),
            buildGpuSamplerDiagModule(),
          ]
        : <FractalModule>[];

    // Merge: catalog first (Mandelbrot at top), then custom, then diag.
    // Insert Julia after Mandelbrot, Phoenix after Burning Ship for UX order.
    final result = <FractalModule>[];

    // Find key positions for insertion
    final mandelbrotIdx =
        catalogModules.indexWhere((m) => m.id == 'mandelbrot');
    final burningShipIdx =
        catalogModules.indexWhere((m) => m.id == 'burning_ship');
    final novaJuliaIdx = catalogModules.indexWhere((m) => m.id == 'nova_julia');

    for (int i = 0; i < catalogModules.length; i++) {
      // Insert Nova right before Nova Julia
      if (i == novaJuliaIdx) {
        final nova = customModules.where((m) => m.id == 'nova');
        result.addAll(nova);
      }
      result.add(catalogModules[i]);
      // Insert Julia and Julia Dual right after Mandelbrot
      if (i == mandelbrotIdx) {
        final julia = customModules.where((m) => m.id == 'julia');
        result.addAll(julia);
        final juliaDual = customModules.where((m) => m.id == 'julia_dual');
        result.addAll(juliaDual);
      }
      // Insert Phoenix right after Burning Ship
      if (i == burningShipIdx) {
        final phoenix = customModules.where((m) => m.id == 'phoenix');
        result.addAll(phoenix);
      }
    }

    // Add remaining custom modules not yet inserted
    for (final m in customModules) {
      if (!result.any((r) => r.id == m.id)) {
        result.add(m);
      }
    }

    // 3D ray-marched catalog modules (KIFS, Quaternion, exotic)
    final raymarched3DModules = buildRaymarched3DCatalogModules();
    result.addAll(raymarched3DModules);

    result.addAll(diagModules);
    // Keep later modules when ids collide so purpose-built 3D catalog entries
    // can replace older placeholder escape-time variants with the same id.
    return _dedupeById(result, preferLast: true);
  }

  static List<FractalModule> _dedupeById(
    List<FractalModule> modules, {
    bool preferLast = false,
  }) {
    if (preferLast) {
      final seen = <String>{};
      final reversedUnique = <FractalModule>[];
      for (final module in modules.reversed) {
        if (seen.add(module.id)) {
          reversedUnique.add(module);
        }
      }
      return reversedUnique.reversed.toList(growable: false);
    }

    final seen = <String>{};
    final unique = <FractalModule>[];
    for (final module in modules) {
      if (seen.add(module.id)) {
        unique.add(module);
      }
    }
    return unique;
  }
}

